const group = new THREE.Group()
const w = widthMm * mm
const h = heightMm * mm
const d = thicknessMm * mm
// Panel occupies XZ plane: X = bay width, Z = panel height, Y = depth
const geo = new THREE.BoxGeometry(w, d, h)
geo.translate(w / 2, d / 2, h / 2)
const mat = new THREE.MeshLambertMaterial({ color: '#D4C4A0' })
group.add(new THREE.Mesh(geo, mat))
return group
